class Solution:
    def deleteGreatestValue(self, grid):
        g = [row[:] for row in grid]
        total = 0
        while g and g[0]:
            round_max = 0
            for row in g:
                idx = row.index(max(row))
                if row[idx] > round_max:
                    round_max = row[idx]
                del row[idx]
            total += round_max
            if not g[0]:
                break
        return total

