var deleteGreatestValue = function(grid) {
    for (const row of grid) row.sort((a, b) => a - b);
    const n = grid[0].length;
    let total = 0;
    for (let c = 0; c < n; c++) {
        let best = 0;
        for (const row of grid) if (row[c] > best) best = row[c];
        total += best;
    }
    return total;
};
